func TestEnumCreateProblemErrorType(t *testing.T) {
	t.Run("NewFromString_generic", func(t *testing.T) {
		t.Parallel()
		val, err := NewCreateProblemErrorTypeFromString("generic")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, CreateProblemErrorType("generic"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewCreateProblemErrorTypeFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewCreateProblemErrorTypeFromString("generic")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

